1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
34	  sword: 1000,
35	  amulet: 600,
36	  rune: 250,
37	};
38	
39	type PolicyState = { items: Item[]; remainingCap: number };
40	
41	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
42	
43	export function runScenario(input: unknown): unknown {
44	  const { customer, steps } = input as Scenario;
45	  const years = customer?.yearsWithMHPCO ?? 0;
46	  const policies: Record<number, PolicyState> = {};
47	  const results = steps.map((step, index) => {
48	    if (step.op === "claim") return computeClaim(step, policies);
49	    return processQuote(step, index, years, policies);
50	  });
51	  return { results };
52	}
53	
54	function processQuote(
55	  step: QuoteStep,
56	  index: number,
57	  years: number,
58	  policies: Record<number, PolicyState>,
59	): { premium: number } {
60	  validateItemTypes(step.items);
61	  const isFollowUp = index >= 1;
62	  policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
63	  return { premium: computePremium(step.items, years, isFollowUp) };
64	}
65	
66	function validateItemTypes(items: Item[]): void {
67	  for (const item of items) {
68	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
69	      throw new Error(`Unknown item type: ${item.type}`);
70	    }
71	  }
72	}
73	
74	function insuranceSumFor(items: Item[]): number {
75	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
76	}
77	
78	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
79	  const policy = policies[step.policy];
80	  rejectIfMoreDamagesThanInsured(step.incident.damages, policy.items);
81	  const uncappedPayout = Math.floor(totalReimbursement(step.incident.damages, policy.items));
82	  const payout = Math.min(uncappedPayout, policy.remainingCap);
83	  policy.remainingCap -= payout;
84	  return { payout, remainingCap: policy.remainingCap };
85	}
86	
87	function rejectIfMoreDamagesThanInsured(damages: Damage[], items: Item[]): void {
88	  const damageCounts = countByKey(damages, (d) => d.itemType);
89	  const itemCounts = countByKey(items, (i) => i.type);
90	  for (const [type, count] of damageCounts) {
91	    if (count > (itemCounts.get(type) ?? 0)) {
92	      throw new Error(`More ${type} damages than insured`);
93	    }
94	  }
95	}
96	
97	function countByKey<T>(values: T[], keyOf: (value: T) => string): Map<string, number> {
98	  const counts = new Map<string, number>();
99	  for (const value of values) {
100	    const key = keyOf(value);
101	    counts.set(key, (counts.get(key) ?? 0) + 1);
102	  }
103	  return counts;
104	}
105	
106	function totalReimbursement(damages: Damage[], items: Item[]): number {
107	  return damages.reduce((sum, damage) => sum + reimbursementFor(damage, items), 0);
108	}
109	
110	function reimbursementFor(damage: Damage, items: Item[]): number {
111	  const item = items.find((i) => i.type === damage.itemType);
112	  if (item === undefined) {
113	    throw new Error(`Damage refers to item type not in policy: ${damage.itemType}`);
114	  }
115	  const rate = isHighlyEnchantedForClaim(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
116	  return Math.max(0, damage.amount * rate - CLAIM_DEDUCTIBLE);
117	}
118	
119	function isHighlyEnchantedForClaim(item: Item): boolean {
120	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
121	}
122	
123	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
124	  if (items.length === 0) return PROCESSING_FEE;
125	  if (items.every(isComponent)) return componentsPremium(items);
126	  return mainItemsPremium(items, years, isFollowUp);
127	}
128	
129	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
130	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
131	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
132	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
133	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
134	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
135	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
136	}
137	
138	function itemSubtotal(item: Item): number {
139	  const base = BASE_PREMIUM_BY_TYPE[item.type];
140	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
141	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
142	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
143	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
144	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
145	}
146	
147	function isHighlyEnchanted(item: Item): boolean {
148	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
149	}
150	
151	function componentsPremium(items: Item[]): number {
152	  const runes = items.filter((i) => i.type === "rune").length;
153	  const moonstones = items.filter((i) => i.type === "moonstone").length;
154	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
155	}
156	
157	function componentTypeBase(count: number): number {
158	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
159	}
160	
161	function isComponent(item: Item): boolean {
162	  return item.type === "rune" || item.type === "moonstone";
163	}
164	
165	function premiumFromBase(base: number): number {
166	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
167	}
